def _build_fonts(size: int) -> tuple[tuple, tuple, tuple]:
    """Build (body, emoji, container) font tuples from a base size."""
    return (
        (_FONT_FAMILY, size),
        (_FONT_EMOJI_FAMILY, size + 3),
        (_FONT_FAMILY, max(size - 2, 6)),
    )


